firmware_template.source:
#include "ble_server.h"
#include <BLEDevice.h>
#include <BLEServer.h>
#include <BLEUtils.h>
#include <BLE2902.h>
#define SERVICE_UUID "4fafc201-1fb5-459e-8fcc-c5c9c331914b"
#define CHAR_UUID    "beb5483e-36e1-4688-b7f5-ea07361b26a8"
static BLECharacteristic* pChar = nullptr;
static bool _connected = false;
class MyCB : public BLEServerCallbacks {
  void onConnect(BLEServer*) { _connected = true; Serial.println("[ble] Connected"); }
  void onDisconnect(BLEServer* s) { _connected = false; s->startAdvertising(); Serial.println("[ble] Disconnected"); }
};
void ble_setup(const char* name) {
  BLEDevice::init(name);
  BLEServer* s = BLEDevice::createServer();
  s->setCallbacks(new MyCB());
  BLEService* svc = s->createService(SERVICE_UUID);
  pChar = svc->createCharacteristic(CHAR_UUID, BLECharacteristic::PROPERTY_READ | BLECharacteristic::PROPERTY_NOTIFY);
  pChar->addDescriptor(new BLE2902());
  svc->start();
  s->getAdvertising()->start();
  Serial.printf("[ble] OK: %s\n", name);
}
void ble_loop() {}
void ble_notify(const char* v) { if (pChar && _connected) { pChar->setValue(v); pChar->notify(); } }
bool ble_is_connected() { return _connected; }
